/* partnerPointSettleMapper.updatePointFileUp */
UPDATE  MSP_PARTNER_POINT_FILE
SET     SEND_FLAG = #{sendFlag}
        , REGST_ID = 'POINT'
        , REGST_DTTM = SYSDATE
WHERE   PARTNER_ID = #{partnerId}
AND     FILE_NM = #{fileNm}

/* partnerPointSettleMapper.updatePointFileDown */
UPDATE  MSP_PARTNER_POINT_FILE
SET     SEND_RESULT = #{sendResult}
        , RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
WHERE   PARTNER_ID = #{partnerId}
AND     FILE_NM = DECODE(#{partnerId}, 'lpoint', REPLACE(#{fileNm}, 'O941', 'O940'), 'lpointP', REPLACE(#{fileNm}, 'O941', 'O940'), #{fileNm})

mapper.select:
/* partnerPointSettleMapper.getPointFileUpList */ SELECT A.PARTNER_ID , A.FILE_NM , A.LOCAL_UP_DIR , A.HOST_UP_DIR FROM MSP_PARTNER_POINT_FILE A WHERE A.SEND_FLAG <> 'S'
AND PARTNER_ID = #{partnerId}
AND FILE_NM LIKE #{fileNm} || '%'

/* partnerPointSettleMapper.getPointFileDownList */
SELECT  A.PARTNER_ID
        , DECODE(A.PARTNER_ID, 'lpoint', REPLACE(A.FILE_NM, 'O940', 'O941'), 'lpointP', REPLACE(A.FILE_NM, 'O940', 'O941'), A.FILE_NM) AS FILE_NM 
        , A.LOCAL_DOWN_DIR
        , A.HOST_DOWN_DIR
FROM    MSP_PARTNER_POINT_FILE A
WHERE   SEND_FLAG = 'S'
AND     SEND_RESULT IN ('R', 'F')

	AND A.PARTNER_ID = #{partnerId}


	AND A.FILE_NM = #{fileNm}

/* partnerPointSettleMapper.getPointFileReadList */
SELECT  A.PARTNER_ID
        , DECODE(A.PARTNER_ID, 'lpoint', REPLACE(A.FILE_NM, 'O940', 'O941'), 'lpointP', REPLACE(A.FILE_NM, 'O940', 'O941'), A.FILE_NM) AS FILE_NM
        , A.LOCAL_DOWN_DIR
FROM    MSP_PARTNER_POINT_FILE A
WHERE   A.SEND_FLAG = 'S'
AND     A.SEND_RESULT = 'D'

	AND A.PARTNER_ID = #{partnerId}


	AND A.FILE_NM = #{fileNm}

/* partnerPointSettleMapper.getPartnerSubList */
SELECT  IF_NO
        , UP_DIR
        , DOWN_DIR
FROM    MSP_PARTNER_SUB
WHERE   IF_NO = #{ifNo}

mapper.delete:
/* partnerPointSettleMapper.deletePointFile */
DELETE FROM MSP_PARTNER_POINT_FILE
WHERE  PARTNER_ID = #{partnerId, jdbcType=VARCHAR}
AND    FILE_NM = #{fileNm, jdbcType=VARCHAR}

