/* partnerPointSettleMapper.updateLPointInterface */
UPDATE  MSP_LPOINT_INTERFACE
SET     RVISN_ID = 'POINT'
        , RVISN_DTTM = SYSDATE
        , DATA_63 = #{resCustNo, jdbcType=VARCHAR}
        , DATA_64 = #{resAprvNo, jdbcType=VARCHAR}
        , DATA_65 = #{resAprvDt, jdbcType=VARCHAR}
        , DATA_66 = #{resAprvTm, jdbcType=VARCHAR}
        , DATA_67 = #{resAprvPoint, jdbcType=VARCHAR}
        , DATA_68 = #{resEvntPoint, jdbcType=VARCHAR}
        , DATA_69 = #{resCd, jdbcType=VARCHAR}
        , DATA_70 = #{resMsg, jdbcType=VARCHAR}
WHERE   LINK_YM = #{linkYm, jdbcType=VARCHAR}
AND     TRIM(DATA_07) = #{customerId, jdbcType=VARCHAR}

